script.text:

function loadFormDir(f) {
	f.setItemValue('form', '');
	if (f._action == 'Edit') setItemDisable(f, 'ma_so', true);
  else if (f._action == 'New') {
			setItemDisable(f, 'ma_so', false);
			onChange$OffFinancialArticles(f, true);
			return;
		}
	onChange$OffFinancialArticles(f);
}
function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_so':
      if (f.getItem('ma_so2').value == '') f.getItem('ma_so2').value = o.value.toUpperCase();
      break;
    case 'kind':
      onChange$OffFinancialArticles(f, true);
      break;
    default:
      break;
  }
}
function onChange$OffFinancialArticles(f, force) {window.setTimeout(String.format('onFocus$OffFinancialArticles(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$OffFinancialArticles(id, force) {
	var f = $find(id);
	v = f.getItem('kind').value, tc = f.getItem('tinh_chat'), nc = f.getItem('no_co');
	switch (v){
		case '0':
			setItemDisable(f, 'no_co, cong_tru, tk, tk_du, tk_0_gt, khong_am, cong_no', true);
			setItemDisable(f, 'tinh_chat, cach_tinh', false);
			if (force){
				setValueForItem(f, 'tinh_chat', '1');
        setItemLive(nc, tc, false);
			}
			break;
		case '1':
			setItemDisable(f, 'tinh_chat, cong_tru, tk_du, tk_0_gt, cach_tinh', true);
			setItemDisable(f, 'no_co, tk, cong_no, khong_am', false);
			if (force){
				setValueForItem(f, 'tinh_chat, no_co, khong_am, cong_no', '1,1,0,0');
        setItemLive(nc, tc, true);
			}
			break;
		case '2':
			setItemDisable(f, 'tinh_chat, khong_am, cong_no, cach_tinh', true);
			setItemDisable(f, 'no_co, cong_tru, tk, tk_du, tk_0_gt', false);
			if (force){
				setValueForItem(f, 'cach_tinh, tinh_chat, no_co, cong_tru', ',2,1,1');
        setItemLive(nc, tc, true);
			}
			break;
		case '9':
			setItemDisable(f, 'no_co, cong_tru, tk, tk_du, tk_0_gt, khong_am, cong_no, cach_tinh', true);
			setItemDisable(f, 'tinh_chat', false);
			if (force){
        setValueForItem(f, 'tinh_chat', '1');
        setItemLive(nc, tc, false);
			}
			break;
		default:
      break;
		}
}
function setItemLive(t1, t2, type) {
  if (type) {
    if (t2.live) {
      t1.disabled = false; 
      t1.focus();
    }
  }
  else {  if (t1.live) {
        t2.disabled = false; 
        t2.focus();
      }
    }
}
function setItemDisable(f, c, v) {
 var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setValueForItem(f, c, v) {
 var a = c.split(','), b = v.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
		o.value = b[i];
  }
}

      &ScriptIrregular;
